<?php
namespace Tests\Feature;
use App\Domain\Hunts\HuntEnemyPersister;use App\Domain\Hunts\HuntService;use App\Models\Character;use App\Models\Hunt;use App\Models\HuntEnemy;use App\Models\User;use App\Models\Zone;use App\Models\ZoneEncounterSize;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use RuntimeException;use Tests\TestCase;
class HuntAtomicityTest extends TestCase{use RefreshDatabase;public function test_failure_after_header_rolls_back_header_and_children(){$this->seed(WorldCatalogSeeder::class);$character=Character::factory()->for(User::factory())->create();$zone=Zone::where('code','grey_oak_forest')->first();ZoneEncounterSize::where('zone_id',$zone->id)->delete();ZoneEncounterSize::create(['zone_id'=>$zone->id,'enemy_count'=>2,'weight'=>100,'is_active'=>true,'sort_order'=>1]);$this->app->instance(HuntEnemyPersister::class,new class extends HuntEnemyPersister{private $calls=0;public function create(Hunt $hunt,array $attributes){$this->calls++;if($this->calls===2)throw new RuntimeException('Controlled persistence failure.');return parent::create($hunt,$attributes);}});try{app(HuntService::class)->start($character,$zone);$this->fail('Expected controlled failure.');}catch(RuntimeException $e){$this->assertSame('Controlled persistence failure.',$e->getMessage());}$this->assertSame(0,Hunt::count());$this->assertSame(0,HuntEnemy::count());}}
